import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Auth from './components/Auth';
import Home from './views/Home';
import Store from './views/Store';
import Support from './views/Support';
import Chat from './views/Chat';
import Profile from './views/Profile';
import Media from './views/Media';
import Community from './views/Community';
import QRScanner from './views/QRScanner';
import Legal from './views/Legal';
import WheelchairAdvisor from './views/WheelchairAdvisor';
import AccessibilityWidget from './components/AccessibilityWidget';
import { ViewState, Product, User, SubscriptionPlan, SubscriptionPeriod } from './types';
import { Search as SearchIcon, X, ArrowLeft, Share2, Check, Banknote, Bitcoin, MessageCircle } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.HOME);
  const [darkMode, setDarkMode] = useState(false);
  const [language, setLanguage] = useState<'ar' | 'en'>('ar');
  const [searchQuery, setSearchQuery] = useState('');
  const [products, setProducts] = useState<Product[]>([]);
  const [shareSuccess, setShareSuccess] = useState(false);
  const [chatTarget, setChatTarget] = useState<{id: string, name: string} | null>(null);
  const [notificationsCount, setNotificationsCount] = useState(0);

  const PRODUCTS_KEY = 'needs_app_products';
  const USER_KEY = 'needs_current_user';

  useEffect(() => {
    const savedProducts = localStorage.getItem(PRODUCTS_KEY);
    if (savedProducts) {
      try { setProducts(JSON.parse(savedProducts)); } catch (e) {}
    }
    const savedUser = localStorage.getItem(USER_KEY);
    if (savedUser) {
        try { setUser(JSON.parse(savedUser)); } catch(e) {}
    }
    if (darkMode) { document.documentElement.classList.add('dark'); } 
    else { document.documentElement.classList.remove('dark'); }
  }, [darkMode]);

  useEffect(() => {
    if (!user) return;
    const timer = setTimeout(() => {
       setNotificationsCount(prev => prev + 1);
    }, 10000);
    return () => clearTimeout(timer);
  }, [user]);

  useEffect(() => {
    document.documentElement.lang = language;
    document.documentElement.dir = language === 'ar' ? 'rtl' : 'ltr';
  }, [language]);

  const toggleLanguage = () => setLanguage(prev => prev === 'ar' ? 'en' : 'ar');
  const handleLogin = (loggedInUser: User) => {
    setUser(loggedInUser);
    localStorage.setItem(USER_KEY, JSON.stringify(loggedInUser));
  };
  const handleLogout = () => {
      setUser(null);
      localStorage.removeItem(USER_KEY);
      setCurrentView(ViewState.HOME);
  };
  const handleUpdateUser = (updatedUser: User) => {
      setUser(updatedUser);
      localStorage.setItem(USER_KEY, JSON.stringify(updatedUser));
  };
  const handleAddProduct = (newProduct: Product) => {
      const updatedProducts = [newProduct, ...products];
      setProducts(updatedProducts);
      localStorage.setItem(PRODUCTS_KEY, JSON.stringify(updatedProducts));
  };
  const handleDeleteProduct = (productId: string) => {
      const updatedProducts = products.filter(p => p.id !== productId);
      setProducts(updatedProducts);
      localStorage.setItem(PRODUCTS_KEY, JSON.stringify(updatedProducts));
      if (selectedProduct && selectedProduct.id === productId) {
          setSelectedProduct(null);
          setCurrentView(ViewState.HOME);
      }
  };
  const handleUpgradeUser = (plan: SubscriptionPlan, period: SubscriptionPeriod) => {
      if (user) {
          const updatedUser: User = { 
              ...user, 
              subscriptionPlan: plan,
              subscriptionPeriod: period,
              subscriptionExpiry: Date.now() + (period === 'DAILY' ? 86400000 : period === 'MONTHLY' ? 2592000000 : 31536000000), 
              points: user.points + (plan === 'ELITE' ? 500 : plan === 'PREMIUM' ? 200 : 50) 
          };
          handleUpdateUser(updatedUser);
      }
  };

  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const handleProductClick = (product: Product) => {
    setSelectedProduct(product);
    setShareSuccess(false);
    setCurrentView(ViewState.PRODUCT_DETAILS);
  };

  const renderView = () => {
    switch (currentView) {
      case ViewState.HOME:
        return <Home products={products} onProductClick={handleProductClick} />;
      case ViewState.ADVISOR:
        return <WheelchairAdvisor products={products} onSelectProduct={handleProductClick} />;
      case ViewState.STORE:
        return <Store products={products} user={user} onUpgrade={handleUpgradeUser} />;
      case ViewState.SUPPORT:
        return <Support />;
      case ViewState.CHAT:
        return <Chat initialTarget={chatTarget} />;
      case ViewState.PROFILE:
        return <Profile user={user} onLogout={handleLogout} onUpdateUser={handleUpdateUser} onViewLegal={() => setCurrentView(ViewState.LEGAL)} />;
      case ViewState.PHOTOS:
        return <Media type="PHOTOS" products={products} user={user} onAddProduct={handleAddProduct} onDeleteProduct={handleDeleteProduct} onChangeView={setCurrentView} />;
      case ViewState.VIDEOS:
        return <Media type="VIDEOS" products={products} user={user} onAddProduct={handleAddProduct} onDeleteProduct={handleDeleteProduct} onChangeView={setCurrentView} />;
      case ViewState.COMMENTS:
        return <Community user={user} />;
      case ViewState.PRODUCT_DETAILS:
        if(!selectedProduct) return <Home products={products} onProductClick={handleProductClick} />;
        return (
            <div className="bg-white dark:bg-gray-800 rounded-2xl overflow-hidden shadow-lg animate-fade-in pb-6">
                <div className="relative h-64 md:h-96 bg-gray-200 dark:bg-black">
                     <button onClick={() => setCurrentView(ViewState.HOME)} className="absolute top-4 right-4 bg-black/50 hover:bg-black/70 text-white p-2 rounded-full z-10">
                         <ArrowLeft size={20} />
                     </button>
                     {selectedProduct.mediaType === 'VIDEO' ? (
                         <video src={selectedProduct.imageUrl} className="w-full h-full object-contain bg-black" controls autoPlay muted playsInline />
                     ) : (
                        <img src={selectedProduct.imageUrl} className="w-full h-full object-cover" alt={selectedProduct.title} />
                     )}
                     <div className={`absolute bottom-4 left-4 px-4 py-2 rounded-xl text-sm font-bold backdrop-blur-md z-10 ${selectedProduct.priceType === 'FREE' ? 'bg-green-500/90 text-white' : 'bg-primary-600/90 text-white'}`}>
                        {selectedProduct.priceType === 'FREE' ? 'مجاني (تبرع)' : `${selectedProduct.price} ${selectedProduct.currency}`}
                     </div>
                </div>
                <div className="p-6">
                    <h1 className="text-2xl font-bold mb-4">{selectedProduct.title}</h1>
                    <div className="prose dark:prose-invert mb-8 text-sm">{selectedProduct.description}</div>
                    <button onClick={() => { setChatTarget({id: selectedProduct.ownerId, name: selectedProduct.ownerName || 'المعلن'}); setCurrentView(ViewState.CHAT); }} className="w-full py-4 bg-primary-600 text-white rounded-xl font-bold flex items-center justify-center gap-2">
                        <MessageCircle size={24} /> تواصل مع المالك
                    </button>
                </div>
            </div>
        );
      case ViewState.SEARCH:
        return <div>صفحة البحث</div>; // تبسيط للعرض
      case ViewState.QR_SCANNER:
        return <QRScanner onClose={() => setCurrentView(ViewState.HOME)} />;
      case ViewState.NOTIFICATIONS:
        return <div>الإشعارات</div>;
      default:
        return <Home products={products} onProductClick={handleProductClick} />;
    }
  };

  return (
    <Layout currentView={currentView} onChangeView={setCurrentView} darkMode={darkMode} toggleDarkMode={() => setDarkMode(!darkMode)} language={language} toggleLanguage={toggleLanguage} notificationsCount={notificationsCount}>
      <AccessibilityWidget />
      {renderView()}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Auth from './components/Auth';
import Home from './views/Home';
import Store from './views/Store';
import Support from './views/Support';
import Chat from './views/Chat';
import Profile from './views/Profile';
import Media from './views/Media';
import Community from './views/Community';
import QRScanner from './views/QRScanner';
import Legal from './views/Legal';
import WheelchairAdvisor from './views/WheelchairAdvisor';
import AccessibilityWidget from './components/AccessibilityWidget';
import { ViewState, Product, User, SubscriptionPlan, SubscriptionPeriod } from './types';
import { Search as SearchIcon, X, ArrowLeft, Share2, Check, Banknote, Bitcoin, MessageCircle } from 'lucide-react';

const App: React.FC = () => {
  const PRODUCTS_KEY = 'needs_app_products';
  const USER_KEY = 'needs_current_user';

  // Synchronously initialize user from localStorage to prevent null pointer errors on first render
  const [user, setUser] = useState<User | null>(() => {
    const savedUser = localStorage.getItem(USER_KEY);
    if (savedUser) {
      try {
        return JSON.parse(savedUser);
      } catch (e) {
        console.error("Failed to parse saved user", e);
        return null;
      }
    }
    return null;
  });

  const [currentView, setCurrentView] = useState<ViewState>(ViewState.HOME);
  const [darkMode, setDarkMode] = useState(false);
  const [language, setLanguage] = useState<'ar' | 'en'>('ar');
  const [products, setProducts] = useState<Product[]>([]);
  const [chatTarget, setChatTarget] = useState<{id: string, name: string} | null>(null);
  const [notificationsCount, setNotificationsCount] = useState(0);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);

  useEffect(() => {
    const savedProducts = localStorage.getItem(PRODUCTS_KEY);
    if (savedProducts) {
      try { setProducts(JSON.parse(savedProducts)); } catch (e) {}
    }
    if (darkMode) { document.documentElement.classList.add('dark'); } 
    else { document.documentElement.classList.remove('dark'); }
  }, [darkMode]);

  useEffect(() => {
    if (!user) return;
    const timer = setTimeout(() => {
       setNotificationsCount(prev => prev + 1);
    }, 10000);
    return () => clearTimeout(timer);
  }, [user]);

  useEffect(() => {
    document.documentElement.lang = language;
    document.documentElement.dir = language === 'ar' ? 'rtl' : 'ltr';
  }, [language]);

  const toggleLanguage = () => setLanguage(prev => prev === 'ar' ? 'en' : 'ar');

  const handleLogin = (loggedInUser: User) => {
    setUser(loggedInUser);
    localStorage.setItem(USER_KEY, JSON.stringify(loggedInUser));
    // After login, take them to the home or previous intended view
    if (currentView === ViewState.AUTH) {
        setCurrentView(ViewState.HOME);
    }
  };

  const handleLogout = () => {
      setUser(null);
      localStorage.removeItem(USER_KEY);
      setCurrentView(ViewState.HOME);
  };

  const handleUpdateUser = (updatedUser: User) => {
      setUser(updatedUser);
      localStorage.setItem(USER_KEY, JSON.stringify(updatedUser));
  };

  const handleAddProduct = (newProduct: Product) => {
      const updatedProducts = [newProduct, ...products];
      setProducts(updatedProducts);
      localStorage.setItem(PRODUCTS_KEY, JSON.stringify(updatedProducts));
  };

  const handleDeleteProduct = (productId: string) => {
      const updatedProducts = products.filter(p => p.id !== productId);
      setProducts(updatedProducts);
      localStorage.setItem(PRODUCTS_KEY, JSON.stringify(updatedProducts));
      if (selectedProduct && selectedProduct.id === productId) {
          setSelectedProduct(null);
          setCurrentView(ViewState.HOME);
      }
  };

  const handleUpgradeUser = (plan: SubscriptionPlan, period: SubscriptionPeriod) => {
      if (user) {
          const updatedUser: User = { 
              ...user, 
              subscriptionPlan: plan,
              subscriptionPeriod: period,
              subscriptionExpiry: Date.now() + (period === 'DAILY' ? 86400000 : period === 'MONTHLY' ? 2592000000 : 31536000000), 
              points: user.points + (plan === 'ELITE' ? 500 : plan === 'PREMIUM' ? 200 : 50) 
          };
          handleUpdateUser(updatedUser);
      }
  };

  const handleProductClick = (product: Product) => {
    setSelectedProduct(product);
    setCurrentView(ViewState.PRODUCT_DETAILS);
  };

  const renderView = () => {
    // Views that are accessible without a user
    if (currentView === ViewState.HOME) return <Home products={products} onProductClick={handleProductClick} />;
    if (currentView === ViewState.SUPPORT) return <Support />;
    if (currentView === ViewState.ADVISOR) return <WheelchairAdvisor products={products} onSelectProduct={handleProductClick} />;
    if (currentView === ViewState.LEGAL) return <Legal onBack={() => setCurrentView(ViewState.PROFILE)} />;

    // Auth Gatekeeper: If user tries to access a protected view without being logged in, show Auth
    if (!user) {
        return <Auth onLogin={handleLogin} />;
    }

    // Protected Views (Only reachable if user is not null)
    switch (currentView) {
      case ViewState.STORE:
        return <Store products={products} user={user} onUpgrade={handleUpgradeUser} />;
      case ViewState.CHAT:
        return <Chat initialTarget={chatTarget} />;
      case ViewState.PROFILE:
        return <Profile user={user} onLogout={handleLogout} onUpdateUser={handleUpdateUser} onViewLegal={() => setCurrentView(ViewState.LEGAL)} />;
      case ViewState.PHOTOS:
        return <Media type="PHOTOS" products={products} user={user} onAddProduct={handleAddProduct} onDeleteProduct={handleDeleteProduct} onChangeView={setCurrentView} />;
      case ViewState.VIDEOS:
        return <Media type="VIDEOS" products={products} user={user} onAddProduct={handleAddProduct} onDeleteProduct={handleDeleteProduct} onChangeView={setCurrentView} />;
      case ViewState.COMMENTS:
        return <Community user={user} />;
      case ViewState.PRODUCT_DETAILS:
        if(!selectedProduct) return <Home products={products} onProductClick={handleProductClick} />;
        return (
            <div className="bg-white dark:bg-gray-800 rounded-2xl overflow-hidden shadow-lg animate-fade-in pb-6">
                <div className="relative h-64 md:h-96 bg-gray-200 dark:bg-black">
                     <button onClick={() => setCurrentView(ViewState.HOME)} className="absolute top-4 right-4 bg-black/50 hover:bg-black/70 text-white p-2 rounded-full z-10">
                         <ArrowLeft size={20} />
                     </button>
                     {selectedProduct.mediaType === 'VIDEO' ? (
                         <video src={selectedProduct.imageUrl} className="w-full h-full object-contain bg-black" controls autoPlay muted playsInline />
                     ) : (
                        <img src={selectedProduct.imageUrl} className="w-full h-full object-cover" alt={selectedProduct.title} />
                     )}
                     <div className={`absolute bottom-4 left-4 px-4 py-2 rounded-xl text-sm font-bold backdrop-blur-md z-10 ${selectedProduct.priceType === 'FREE' ? 'bg-green-500/90 text-white' : 'bg-primary-600/90 text-white'}`}>
                        {selectedProduct.priceType === 'FREE' ? 'مجاني (تبرع)' : `${selectedProduct.price} ${selectedProduct.currency}`}
                     </div>
                </div>
                <div className="p-6">
                    <h1 className="text-2xl font-bold mb-4">{selectedProduct.title}</h1>
                    <div className="prose dark:prose-invert mb-8 text-sm">{selectedProduct.description}</div>
                    <button onClick={() => { setChatTarget({id: selectedProduct.ownerId, name: selectedProduct.ownerName || 'المعلن'}); setCurrentView(ViewState.CHAT); }} className="w-full py-4 bg-primary-600 text-white rounded-xl font-bold flex items-center justify-center gap-2">
                        <MessageCircle size={24} /> تواصل مع المالك
                    </button>
                </div>
            </div>
        );
      case ViewState.QR_SCANNER:
        return <QRScanner onClose={() => setCurrentView(ViewState.HOME)} />;
      default:
        return <Home products={products} onProductClick={handleProductClick} />;
    }
  };

  return (
    <Layout 
      currentView={currentView} 
      onChangeView={setCurrentView} 
      darkMode={darkMode} 
      toggleDarkMode={() => setDarkMode(!darkMode)} 
      language={language} 
      toggleLanguage={toggleLanguage} 
      notificationsCount={notificationsCount}
    >
      <AccessibilityWidget />
      {renderView()}
    </Layout>
  );
};

export default App;

import React, { useRef, useState, useEffect } from 'react';
import { User } from '../types';
import { MapPin, Award, Share2, CreditCard, Camera, LogOut, Edit2, Check, X, Shield, FileText } from 'lucide-react';

interface ProfileProps {
    user: User;
    onLogout: () => void;
    onUpdateUser?: (updatedUser: User) => void;
    onViewLegal: () => void;
}

const Profile: React.FC<ProfileProps> = ({ user, onLogout, onUpdateUser, onViewLegal }) => {
  // Safety guard for null user (should be handled by parent, but good for robustness)
  if (!user) {
    return (
      <div className="flex flex-col items-center justify-center py-20 text-gray-500">
        <p>يرجى تسجيل الدخول لعرض الملف الشخصي</p>
      </div>
    );
  }

  const [avatar, setAvatar] = useState(user.avatar || 'https://ui-avatars.com/api/?name=' + encodeURIComponent(user.fullName) + '&background=random');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Edit Mode State
  const [isEditing, setIsEditing] = useState(false);
  const [shareSuccess, setShareSuccess] = useState(false);
  const [editForm, setEditForm] = useState({
      fullName: user.fullName,
      location: user.location,
      bio: user.bio || ''
  });

  useEffect(() => {
     if(user.avatar) setAvatar(user.avatar);
     setEditForm({
         fullName: user.fullName,
         location: user.location,
         bio: user.bio || ''
     });
  }, [user]);

  const handleAvatarChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
          const result = reader.result as string;
          setAvatar(result);
          if (onUpdateUser) {
              onUpdateUser({ ...user, avatar: result });
          }
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSaveProfile = () => {
      if (onUpdateUser) {
          onUpdateUser({
              ...user,
              fullName: editForm.fullName,
              location: editForm.location,
              bio: editForm.bio
          });
      }
      setIsEditing(false);
  };

  const handleShareProfile = async () => {
    const shareData = {
        title: `ملف ${user.fullName} على needs`,
        text: `تصفح ملف ${user.fullName} في تطبيق needs للمساعدة والدعم.`,
        url: window.location.href 
    };

    // Construct clean URL for sharing
    const urlObj = new URL(window.location.origin);
    urlObj.searchParams.set('profile', user.id);
    shareData.url = urlObj.toString();

    if (navigator.share) {
        try {
            await navigator.share(shareData);
        } catch (err: any) {
            if (err.name !== 'AbortError') {
                console.error("Error sharing:", err);
            }
        }
    } else {
        try {
            await navigator.clipboard.writeText(shareData.url);
            setShareSuccess(true);
            setTimeout(() => setShareSuccess(false), 2000);
        } catch (err) {
            console.error("Error copying:", err);
        }
    }
  };

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Header Card */}
      <div className="bg-white dark:bg-gray-800 rounded-2xl p-6 shadow-sm relative border border-gray-100 dark:border-gray-700">

        {/* Top Actions */}
        <div className="absolute top-4 left-4 flex gap-2">
            <button 
                onClick={onLogout}
                className="text-gray-400 hover:text-red-500 transition-colors p-2"
                title="تسجيل الخروج"
            >
                <LogOut size={20} />
            </button>
        </div>

        <div className="absolute top-4 right-4">
            {isEditing ? (
                <div className="flex gap-2">
                    <button onClick={handleSaveProfile} className="bg-green-500 text-white p-2 rounded-full shadow hover:bg-green-600">
                        <Check size={18} />
                    </button>
                    <button onClick={() => setIsEditing(false)} className="bg-gray-200 dark:bg-gray-700 text-gray-600 dark:text-gray-300 p-2 rounded-full hover:bg-gray-300">
                        <X size={18} />
                    </button>
                </div>
            ) : (
                <button onClick={() => setIsEditing(true)} className="bg-primary-50 dark:bg-primary-900/20 text-primary-600 p-2 rounded-full hover:bg-primary-100 transition-colors">
                    <Edit2 size={18} />
                </button>
            )}
        </div>

        {/* Avatar */}
        <div className="relative w-24 h-24 mx-auto mb-4 group">
          <div className="w-full h-full rounded-full overflow-hidden border-4 border-primary-100 dark:border-primary-900 shadow-inner">
            <img src={avatar} alt="Profile" className="w-full h-full object-cover" />
          </div>
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="absolute bottom-0 right-0 bg-primary-600 text-white p-2 rounded-full shadow-md hover:bg-primary-700 transition-all transform hover:scale-110"
            title="تغيير الصورة الشخصية"
          >
            <Camera size={16} />
          </button>
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleAvatarChange} 
            accept="image/*" 
            className="hidden" 
          />
        </div>

        {/* Info Fields */}
        <div className="text-center">
            {isEditing ? (
                <div className="space-y-3 max-w-xs mx-auto mb-4">
                    <input 
                        type="text"
                        value={editForm.fullName}
                        onChange={(e) => setEditForm({...editForm, fullName: e.target.value})}
                        className="w-full text-center p-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-gray-50 dark:bg-gray-700 text-gray-900 dark:text-white font-bold"
                        placeholder="الاسم الكامل"
                    />
                    <input 
                        type="text"
                        value={editForm.location}
                        onChange={(e) => setEditForm({...editForm, location: e.target.value})}
                        className="w-full text-center p-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-gray-50 dark:bg-gray-700 text-sm"
                        placeholder="الموقع (المدينة، الدولة)"
                    />
                     <textarea 
                        value={editForm.bio}
                        onChange={(e) => setEditForm({...editForm, bio: e.target.value})}
                        className="w-full text-center p-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-gray-50 dark:bg-gray-700 text-sm resize-none"
                        placeholder="اكتب نبذة عنك..."
                        rows={2}
                    />
                </div>
            ) : (
                <>
                    <h2 className="text-xl font-bold text-gray-900 dark:text-white">{user.fullName}</h2>
                    <p className="text-primary-600 text-sm font-medium dir-ltr mb-2">{user.username}</p>
                    <div className="flex items-center justify-center gap-2 text-gray-500 dark:text-gray-400 text-sm mb-2">
                        <MapPin size={14} />
                        {user.location || 'الموقع غير محدد'}
                    </div>
                    {user.bio && (
                        <p className="text-gray-600 dark:text-gray-300 text-sm max-w-sm mx-auto mb-4 italic">
                            "{user.bio}"
                        </p>
                    )}
                </>
            )}
        </div>

        <div className="flex justify-center gap-4 border-t border-gray-100 dark:border-gray-700 pt-4 mt-4">
           <div className="text-center px-4">
             <div className="font-bold text-lg dark:text-white">{user.points}</div>
             <div className="text-xs text-gray-400">نقاط</div>
           </div>
           <div className="w-px bg-gray-200 dark:bg-gray-700"></div>
           <div className="text-center px-4">
             <div className="font-bold text-lg dark:text-white">{user.subscriptionPlan !== 'FREE' ? '∞' : '3'}</div>
             <div className="text-xs text-gray-400">إعلان يومي</div>
           </div>
           <div className="w-px bg-gray-200 dark:bg-gray-700"></div>
           <div className="text-center px-4">
             <div className="font-bold text-lg dark:text-white">5.0</div>
             <div className="text-xs text-gray-400">تقييم</div>
           </div>
        </div>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-2 gap-4">
        <div className="bg-gradient-to-br from-yellow-500 to-orange-600 rounded-2xl p-4 text-white shadow-md relative overflow-hidden">
           <div className="absolute -right-4 -bottom-4 opacity-20">
               <Award size={64} />
           </div>
           <Award size={24} className="mb-2 opacity-90" />
           <div className="font-bold text-2xl">{user.points}</div>
           <div className="text-xs opacity-90">رصيد النقاط المكتسبة</div>
        </div>
        <div className="bg-gradient-to-br from-green-500 to-emerald-600 rounded-2xl p-4 text-white shadow-md relative overflow-hidden">
           <div className="absolute -right-4 -bottom-4 opacity-20">
               <CreditCard size={64} />
           </div>
           <CreditCard size={24} className="mb-2 opacity-90" />
           <div className="font-bold text-xl">{user.subscriptionPlan === 'FREE' ? 'مجانية' : user.subscriptionPlan}</div>
           <div className="text-xs opacity-90">
               {user.subscriptionPlan === 'FREE' ? 'ترقية الحساب' : `${user.subscriptionPeriod || ''} - نشط`}
           </div>
        </div>
      </div>

      {/* Legal & Privacy Link */}
      <button 
        onClick={onViewLegal}
        className="w-full bg-white dark:bg-gray-800 p-4 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 flex items-center justify-between hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"
      >
        <div className="flex items-center gap-3">
             <div className="bg-blue-100 dark:bg-blue-900/30 text-primary-600 p-2 rounded-full">
                <Shield size={20} />
             </div>
             <span className="font-bold text-gray-800 dark:text-gray-200">السياسة والخصوصية</span>
        </div>
        <FileText size={18} className="text-gray-400" />
      </button>

      {/* QR Code */}
       <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm flex flex-col items-center border border-gray-100 dark:border-gray-700">
          <h3 className="font-bold mb-4 text-sm text-gray-500 dark:text-gray-400">بطاقة الملف الشخصي</h3>
          <div className="bg-white p-2 rounded-lg border border-gray-200 mb-4">
             <img src={`https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=user:${user.id}`} alt="QR Code" className="w-32 h-32 mix-blend-multiply" />
          </div>
          <button 
            onClick={handleShareProfile}
            className={`flex items-center gap-2 text-sm font-bold hover:underline transition-colors ${shareSuccess ? 'text-green-600' : 'text-primary-600 dark:text-primary-400'}`}
          >
            {shareSuccess ? <Check size={16} /> : <Share2 size={16} />}
            {shareSuccess ? 'تم نسخ الرابط' : 'مشاركة الرابط'}
          </button>
       </div>
    </div>
  );
};

